INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('0e679e75-5ee7-5858-b3cf-9ea34f016d0f', 'd356a77a-a6db-48bc-b463-059038ee9d4b', 'She was ___ to the new rules, so there was no conflict in the classroom.', '她欣然贊同新的規則，因此教室裡沒有發生衝突。', 'agreeable', 'aggressive', 'anxious', 'awkward', 'agree (同意) + -able (形容詞字尾，表示「可以...的」) → agreeable (欣然贊同的、隨和的)', '記住 agree 是「同意」，加上 -able 變成「可以被同意的」，引申為「欣然贊同的」。', '2026-07-06 19:15:55', '2026-07-06 19:15:55'),
('8e3e43f4-fa9f-503a-8265-5a8147124de7', '2bdd37b4-7119-4845-9f84-d23458a5cc22', 'As the athletes entered the stadium, the crowd stood up in silence to sing the national ___.', '當運動員進入體育場時，群眾肅立著唱起國歌。', 'anthem', 'speech', 'prayer', 'poem', 'anthem 源自希臘語，原意指「回應式的歌唱」，現代英文中指「國歌」或「頌歌」。', '想像在大型運動會或國家典禮上，大家集體高唱 anthem (國歌) 的莊嚴場面。', '2026-07-06 21:47:15', '2026-07-06 21:47:15'),
('364fff04-4c8a-57be-b7ae-a6a9a90dcd07', 'f45b6ee1-19f8-4299-8a78-b41f769975ee', 'Researchers must consult the national ___ to find primary sources for their studies on ancient civilizations.', '研究人員必須查閱國家檔案館，以尋找有關古代文明研究的一手資料。', 'archive', 'museum', 'library', 'gallery', '詞根 arch- → ancient (古老的)，在此指存放古老紀錄的檔案館。', 'archive 讀音接近「阿其夫」，想像把「古老」的「檔案」存放在裡面。', '2026-07-06 23:39:43', '2026-07-06 23:39:43'),
('8d1ffc9c-b94f-5205-a495-692c20027faf', 'f62a397a-4ce1-4510-be2e-4403218c1bec', 'The doctor warned him that cold weather and sudden changes in temperature could trigger his ___.', '醫生警告他，寒冷的天氣和溫度的突然變化可能會誘發他的氣喘。', 'asthma', 'diabetes', 'anemia', 'migraine', '源自希臘語 astma，意指呼吸困難或喘息。', '想像在寒冷空氣中呼吸變得非常困難，只能不斷「喘」氣 → asthma (氣喘)。', '2026-07-07 01:35:01', '2026-07-07 01:35:01'),
('746ed822-0c27-5376-be78-aa592b5ceb93', '57938815-4518-4089-87d7-f7e8ab237dda', 'Since she is my father''s sister, my ___ always tells me fascinating stories about his childhood.', '因為她是我的父親的姊妹，我的姑媽總是跟我講關於他童年時期的迷人故事。', 'aunt', 'cousin', 'neighbor', 'teacher', 'aunt 為名詞，指女性親屬（如姨媽、姑媽、嬸嬸等）。', 'aunt (姨媽/姑媽) → 聯想一位女性長輩在分享家族往事。', '2026-07-07 03:36:42', '2026-07-07 03:36:42'),
('e99fbc8a-d4c6-55c2-9708-673899f0be83', 'cd6474a2-b77c-417b-a43b-dc267c741870', 'My father doesn''t like ___ because it is too bitter.', '我父親不喜歡咖啡，因為它太苦了。', 'coffee', 'milk', 'water', 'soda', 'Coffee 為名詞，代表一種常見的飲品。', '咖啡的味道很特別，苦苦的，喝完會提神。', '2026-07-07 05:00:07', '2026-07-07 05:00:07'),
('4a9aa436-4a94-596d-8d48-d408c1eff067', 'd29c6fee-cb25-4db1-920f-455a223c1044', 'The company plans to ___ more workers next summer.', '這家公司計畫在明年夏天僱用更多工人。', 'employ', 'enjoy', 'escape', 'expect', 'em- (使...) + ploy (使用) → 使某人使用其技能 → 僱用', '聯想 employer (僱主)，公司要 em- (使) 人 ploy (工作) → 僱用。', '2026-07-07 03:45:51', '2026-07-07 03:45:51'),
('8e2c0434-983a-594b-9008-008ba7ee7f87', '13eb922f-d226-4de0-9721-0d88ccf7610e', 'The bottle is ___; there is no water left inside.', '這個瓶子是空的；裡面沒有水了。', 'empty', 'full', 'heavy', 'dirty', 'empty 為形容詞，表示「空的」。', '想像一個 empty box (空盒子)，裡面什麼都沒有。', '2026-07-07 03:46:24', '2026-07-07 03:46:24'),
('4d3156db-10f9-581f-b776-d6ac63d0a573', '0029c202-89d5-4e49-bf5e-5d9f68f81b93', 'The road is not ___ so please drive slowly.', '這條路不平坦，所以請慢速行駛。', 'even', 'tall', 'wide', 'long', 'even (adj.) 平坦的、平整的。', 'even 有平整的意思，想像一個 even 的桌面不會讓杯子倒掉。', '2026-07-07 04:21:05', '2026-07-07 04:21:05'),
('6581b239-e8f2-519e-8500-805fdd08ae7f', '74821cee-378a-4b2f-9608-9d3068e5413f', 'If you eat too much junk food, you might become ___.', '如果你吃太多垃圾食物，你可能會變得胖胖的。', 'fat', 'thin', 'tall', 'fast', 'fat 為基礎單字，形容詞用法表示胖的，名詞用法表示脂肪。', '聯想發音 fat 像發，胖的人看起來很發福。', '2026-07-07 05:08:10', '2026-07-07 05:08:10'),
('03800a25-d8af-5e0a-8f38-49cd0c70fbc7', 'ad050278-a913-4be5-b0bb-d3d91b5aa55b', 'I have never tried surfing before, but I would like to have a ___ this summer.', '我以前從沒試過衝浪，但今年夏天我想嘗試看看。', 'go', 'way', 'time', 'luck', 'go (n.) 表示嘗試或機會。', '去嘗試做一件新事物。', '2026-07-05 08:01:37', '2026-07-05 08:01:37');
